# auth_utils.pyfrom typing import Optionalfrom fastapi import Depends, HTTPException, status, Cookie, Headerfrom fastapi.security import OAuth2PasswordBearerfrom jose import JWTErrorfrom sqlalchemy.orm import Sessionfrom database import get_dbfrom models import Userfrom security import decode_tokenimport logging# Match your actual routeoauth2_scheme = OAuth2PasswordBearer(    tokenUrl="/auth/token",    auto_error=False,)def get_current_user(    token_header: Optional[str] = Depends(oauth2_scheme),         # Bearer from OAuth2 flow    authorization: Optional[str] = Header(None),                  # raw Authorization header fallback    token_cookie: Optional[str] = Cookie(None, alias="access_token"),  # <-- set to your real cookie name    db: Session = Depends(get_db),) -> User:    # Try OAuth2 extracted token, then cookie, then raw header    token = token_header or token_cookie    if not token and authorization and authorization.lower().startswith("bearer "):        token = authorization.split(" ", 1)[1].strip()    if not token:        raise HTTPException(            status_code=status.HTTP_401_UNAUTHORIZED,            detail="Not authenticated",            headers={"WWW-Authenticate": "Bearer"},        )    try:        payload = decode_token(token)        user_id = int(payload.get("sub", "0"))    except JWTError:        raise HTTPException(            status_code=status.HTTP_401_UNAUTHORIZED,            detail="Invalid or expired token",            headers={"WWW-Authenticate": "Bearer"},        )    user = db.get(User, user_id)    if not user:        raise HTTPException(            status_code=status.HTTP_401_UNAUTHORIZED,            detail="User not found",        )    return userdef require_admin(user: User = Depends(get_current_user)) -> User:    if not getattr(user, "is_admin", False):        raise HTTPException(            status_code=status.HTTP_403_FORBIDDEN,            detail="Admin privileges required",        )    return user